// ============================================================
// FLAT SECTIONS for backward compat (one section per machine)
// ============================================================
export const SECTIONS = GROUPS.flatMap(g =>
  g.machines.map(m => ({
    id: `${g.id}__${m.machine}`,
    group: g.id,
    groupTitle: g.title,
    title: m.machine.replace(/_/g, " "),
    dashboard: m.machine,
    params: m.params,
  }))
);

